// 解析 GPT-4 回傳的 JSON
const response = $input.first().json;
const content = response.choices[0].message.content;

let data;
try {
  data = JSON.parse(content);
} catch (e) {
  data = { articles: [], insight: content };
}

// 日期格式化
const today = new Date().toLocaleDateString('zh-TW', {
  year: 'numeric',
  month: '2-digit',
  day: '2-digit'
});

// 依類別分組
const automationArticles = (data.articles || []).filter(a =>
  a.category && a.category.includes('自動化')
);
const voiceArticles = (data.articles || []).filter(a =>
  a.category && a.category.includes('語音')
);
// 未分類的文章平均分配
const uncat = (data.articles || []).filter(a =>
  !a.category || (!a.category.includes('自動化') && !a.category.includes('語音'))
);
const mid = Math.ceil(uncat.length / 2);
const autoList = [...automationArticles, ...uncat.slice(0, mid)];
const voiceList = [...voiceArticles, ...uncat.slice(mid)];

// 渲染文章卡片
const renderArticles = (articles) => {
  if (!articles.length) {
    return '<p style="color:#888;font-style:italic;margin:0;">今日暫無相關新聞</p>';
  }
  return articles.map(a => `
    <div style="border:1px solid #e0e0e0;border-radius:6px;padding:20px 24px;margin-bottom:14px;background:#ffffff;">
      <h3 style="margin:0 0 10px;font-size:15px;font-weight:700;color:#111;line-height:1.5;">
        <a href="${a.url}" style="color:#111;text-decoration:none;" target="_blank">${a.title}</a>
      </h3>
      <p style="margin:0 0 14px;font-size:14px;color:#555;line-height:1.8;">${a.summary}</p>
      <a href="${a.url}" style="font-size:12px;color:#777;text-decoration:underline;letter-spacing:0.3px;" target="_blank">閱讀完整報導 →</a>
    </div>
  `).join('');
};

// 生成完整 HTML
const html = `<!DOCTYPE html>
<html lang="zh-TW">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>AI 新聞日報 ${today}</title>
</head>
<body style="margin:0;padding:0;background:#f0f0f0;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI','Helvetica Neue',Arial,sans-serif;">

  <div style="max-width:660px;margin:0 auto;padding:28px 16px;">

    <!-- Header -->
    <div style="background:#111111;color:#ffffff;padding:36px 32px;border-radius:8px;margin-bottom:28px;">
      <div style="font-size:10px;letter-spacing:4px;text-transform:uppercase;color:#888;margin-bottom:10px;">DAILY DIGEST</div>
      <h1 style="margin:0 0 8px;font-size:30px;font-weight:800;letter-spacing:-0.5px;line-height:1.2;">AI 新聞日報</h1>
      <div style="font-size:13px;color:#aaa;">${today}&nbsp;&nbsp;·&nbsp;&nbsp;過去 24 小時精選</div>
    </div>

    <!-- AI 自動化 -->
    <div style="margin-bottom:32px;">
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:18px;">
        <div style="width:4px;height:24px;background:#111;border-radius:2px;"></div>
        <h2 style="margin:0;font-size:20px;font-weight:800;color:#111;letter-spacing:-0.3px;">AI 自動化</h2>
      </div>
      ${renderArticles(autoList)}
    </div>

    <!-- AI 語音 -->
    <div style="margin-bottom:32px;">
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:18px;">
        <div style="width:4px;height:24px;background:#111;border-radius:2px;"></div>
        <h2 style="margin:0;font-size:20px;font-weight:800;color:#111;letter-spacing:-0.3px;">AI 語音</h2>
      </div>
      ${renderArticles(voiceList)}
    </div>

    <!-- 今日重點觀察 -->
    <div style="background:#111111;color:#ffffff;padding:28px 32px;border-radius:8px;margin-bottom:28px;">
      <div style="font-size:10px;letter-spacing:4px;text-transform:uppercase;color:#777;margin-bottom:12px;">TODAY'S INSIGHT</div>
      <h3 style="margin:0 0 14px;font-size:15px;font-weight:700;color:#fff;">今日重點觀察</h3>
      <p style="margin:0;font-size:15px;color:#ccc;line-height:1.9;">${data.insight || '今日無特別觀察'}</p>
    </div>

    <!-- Footer -->
    <div style="text-align:center;padding:8px 0;">
      <p style="margin:0;font-size:11px;color:#aaa;letter-spacing:0.5px;">由 n8n · GPT-4 · Tavily 自動生成 &nbsp;|&nbsp; ${today}</p>
    </div>

  </div>
</body>
</html>`;

return [{
  json: {
    html,
    subject: `AI 新聞日報 | ${today}`
  }
}];
